import streamlit as stimport pandas as pdimport plotly.express as pximport plotly.graph_objects as gofrom datetime import datetime# --- 1. KURUMSAL VE TEKNİK YAPILANDIRMA ---st.set_page_config(    page_title="Focus AI | Master Coach & ERP",     layout="wide",     initial_sidebar_state="expanded")# --- 2. GÜNCEL STRATEJİK MÜFREDAT (2021-2025 SORU ANALİZLİ) ---STRATEJIK_MUFREDAT = {    "TYT Türkçe": {        "Paragraf (26 Soru)": 26, "Cümlede Anlam (3 Soru)": 3, "Sözcükte Anlam (3 Soru)": 3,         "Yazım Kuralları (2 Soru)": 2, "Noktalama İşaretleri (2 Soru)": 2, "Dil Bilgisi (4 Soru)": 4    },    "TYT Matematik": {        "Problemler (12 Soru)": 12, "Temel Kavramlar (3 Soru)": 3, "Sayı Basamakları (2 Soru)": 2,        "Rasyonel Sayılar (1 Soru)": 1, "Denklemler (1 Soru)": 1, "Üslü/Köklü (2 Soru)": 2,        "Kümeler/Mantık (2 Soru)": 2, "Fonksiyonlar (1 Soru)": 1    },    "AYT Matematik": {        "Türev (4 Soru)": 4, "İntegral (4 Soru)": 4, "Trigonometri (4 Soru)": 4,         "Logaritma (2 Soru)": 2, "Limit (2 Soru)": 2, "Diziler (1 Soru)": 1, "Polinomlar (1 Soru)": 1    },    "AYT Edebiyat": {        "Divan Edebiyatı (5 Soru)": 5, "Cumhuriyet Dönemi (4 Soru)": 4, "Şiir Bilgisi (3 Soru)": 3,         "Edebi Sanatlar (2 Soru)": 2, "Halk Edebiyatı (2 Soru)": 2, "Tanzimat/Servet-i Fünun (3 Soru)": 3    },    "Geometri (TYT/AYT)": {        "Üçgenler (2 Soru)": 2, "Çokgenler (2 Soru)": 2, "Analitik (2 Soru)": 2, "Katı Cisimler (2 Soru)": 2, "Çember/Daire (2 Soru)": 2    },    "Fen Bilimleri (TYT/AYT)": {        "Sistemler (Bio) (4 Soru)": 4, "Modern Fizik (2 Soru)": 2, "Organik Kimya (3 Soru)": 3,         "Elektrik/Manyetizma (3 Soru)": 3, "Optik (1 Soru)": 1, "Kalıtım (1 Soru)": 1    }}# --- 3. REHBERLİK & PDR ENVANTERLERİ ---REHBERLIK_SORULARI = {    "VAK Öğrenme Stilleri": ["Not tutmayı severim.", "Görsel şemalarla daha iyi anlarım.", "Ders dinlerken hareket ihtiyacı duyarım."],    "Sınav Kaygısı Ölçeği": ["Sınavda ellerim titrer/terler.", "Sınav öncesi uyuyamam.", "Unutma korkusu yaşarım."],    "Odaklanma ve Dikkat Testi": ["Ufak bir ses dikkatimi dağıtır.", "Bir işi bitirmeden diğerine geçerim.", "Uzun süre odaklanmak beni yorar."],    "Akademik Özgüven": ["Zorlandığımda pes etmem.", "Hatalarımdan ders alırım.", "Hedefime inanırım."]}# --- 4. MERKEZİ HAFIZA SİSTEMİ (SESSION STATE) ---for key in ['ogrenciler', 'program', 'video_odevler', 'test_sonuclari', 'koc_notlari', 'soru_takip', 'kitap_takibi']:    if key not in st.session_state:        if key == 'ogrenciler':            st.session_state[key] = pd.DataFrame(columns=["Ad Soyad", "Alan", "Hedef Puan", "Veli Tel"])        elif key == 'program':            st.session_state[key] = pd.DataFrame(columns=["Öğrenci", "Ders", "Konu", "Soru Yükü", "Durum", "Tarih"])        elif key == 'video_odevler':            st.session_state[key] = pd.DataFrame(columns=["Öğrenci", "Başlık", "Link", "Durum"])        elif key == 'test_sonuclari':            st.session_state[key] = pd.DataFrame(columns=["Tarih", "Öğrenci", "Test Adı", "Skor"])        elif key == 'koc_notlari':            st.session_state[key] = pd.DataFrame(columns=["Tarih", "Öğrenci", "Not", "Etiket"])        elif key == 'soru_takip':            st.session_state[key] = pd.DataFrame(columns=["Tarih", "Öğrenci", "Ders", "D", "Y", "B"])        elif key == 'kitap_takibi':            st.session_state[key] = pd.DataFrame(columns=["Öğrenci", "Kitap", "Toplam Test", "Tamamlanan"])        else:            st.session_state[key] = pd.DataFrame()# --- 5. NAVİGASYON ---st.sidebar.title("🎯 Focus AI v13.0")st.sidebar.caption("Bostanlı Çözüm VIP - Master Edition")role = st.sidebar.radio("SİSTEM PANELİ", ["👨‍🏫 KOÇLUK & YÖNETİM", "🎓 ÖĞRENCİ PORTALI"])ogrenci_listesi = st.session_state.ogrenciler["Ad Soyad"].tolist() if not st.session_state.ogrenciler.empty else ["Öğrenci Yok"]# ==========================================# 👨‍🏫 MODÜL 1: KOÇLUK & YÖNETİM# ==========================================if role == "👨‍🏫 KOÇLUK & YÖNETİM":    st.title("🏛️ Master Coach Operasyon Merkezi")    tabs = st.tabs(["📋 Stratejik Planlama", "🧠 Rehberlik & PDR", "📊 Başarı Ligi & Radar", "👤 Kayıt & Veli", "📺 Video & Kitap"])    with tabs[0]: # STRATEJİK PLANLAMA (DİNAMİK FİLTRELEME FİX)        st.subheader("🛠️ ÖSYM Odaklı Müfredat Atama")        c1, c2 = st.columns(2)        o_at = c1.selectbox("Öğrenci Seç", ogrenci_listesi, key="o_koc")        d_at = c2.selectbox("Ders Seçin", list(STRATEJIK_MUFREDAT.keys()), key="d_koc")                # Dinamik Konu Listesi: Ders seçildiği an güncellenir        konu_ops = list(STRATEJIK_MUFREDAT[d_at].keys())        k_at = st.multiselect("Konu(lar) (Soru Sayısı Yanında)", konu_ops, key="k_koc")                if st.button("Haftalık Programa Ekle"):            if o_at != "Öğrenci Yok" and k_at:                for k in k_at:                    s_y = STRATEJIK_MUFREDAT[d_at][k]                    yeni_p = pd.DataFrame([[o_at, d_at, k, s_y, "Bekliyor", datetime.now()]], columns=st.session_state.program.columns)                    st.session_state.program = pd.concat([st.session_state.program, yeni_p], ignore_index=True)                st.success(f"{len(k_at)} konu başarıyla iletildi!")                st.rerun()    with tabs[1]: # REHBERLİK & PDR        st.subheader("🧠 Rehberlik Test Analizleri ve Görüşme Notları")        c_p1, c_p2 = st.columns([2, 1])        with c_p1:            st.write("#### Test Sonuçları")            st.dataframe(st.session_state.test_sonuclari, use_container_width=True)        with c_p2:            st.write("#### Koçluk Notu Ekle")            with st.form("not_f"):                n_o = st.selectbox("Öğrenci", ogrenci_listesi)                n_t = st.text_area("Görüşme Notu...")                if st.form_submit_button("Notu Kaydet"):                    yeni_n = pd.DataFrame([[datetime.now().strftime("%d/%m"), n_o, n_t, "Genel"]], columns=st.session_state.koc_notlari.columns)                    st.session_state.koc_notlari = pd.concat([st.session_state.koc_notlari, yeni_n], ignore_index=True)                    st.success("Not kaydedildi.")    with tabs[2]: # BAŞARI LİGİ & RADAR        col_l1, col_l2 = st.columns(2)        with col_l1:            st.subheader("🏆 Focus Başarı Ligi")            if not st.session_state.program.empty:                lig = st.session_state.program[st.session_state.program["Durum"] == "Tamamlandı"].groupby("Öğrenci")["Soru Yükü"].sum().reset_index()                st.table(lig.sort_values("Soru Yükü", ascending=False))        with col_l2:            st.subheader("🕸️ Gelişim Radarı")            fig_r = go.Figure(data=go.Scatterpolar(r=[85, 75, 90, 60, 80], theta=['Akademik', 'Odak', 'Hız', 'Mental', 'Düzen'], fill='toself'))            st.plotly_chart(fig_r, use_container_width=True)    with tabs[3]: # KAYIT & VELİ        st.subheader("👤 Öğrenci Kayıt ve WhatsApp Raporu")        with st.form("kayit_f"):            c1, c2, c3 = st.columns(3)            na = c1.text_input("Ad Soyad")            nh = c2.number_input("Hedef Puan", 200, 500, 450)            nt = c3.text_input("Veli Tel (905...)")            if st.form_submit_button("Kaydet"):                yeni_o = pd.DataFrame([[na, "Sayısal", nh, nt]], columns=st.session_state.ogrenciler.columns)                st.session_state.ogrenciler = pd.concat([st.session_state.ogrenciler, yeni_o], ignore_index=True)                st.rerun()                if not st.session_state.ogrenciler.empty:            sel_o = st.selectbox("Rapor Gönderilecek Öğrenci", ogrenci_listesi)            tel = st.session_state.ogrenciler[st.session_state.ogrenciler["Ad Soyad"] == sel_o]["Veli Tel"].values[0]            st.link_button("🟢 WhatsApp'tan Rapor Gönder", f"https://wa.me/{tel}?text=FocusAI%20Raporu%3A%20Gelisim%20pozitif.")    with tabs[4]: # VİDEO & KİTAP        st.subheader("📺 İçerik Atama")        c1, c2 = st.columns(2)        with c1:            st.write("#### Video Ödevi")            v_o = st.selectbox("Öğrenci", ogrenci_listesi, key="v_k")            v_l = st.text_input("YouTube Linki")            if st.button("Videoyu Gönder"):                yeni_v = pd.DataFrame([[v_o, "Önemli Video", v_l, "Bekliyor"]], columns=st.session_state.video_odevler.columns)                st.session_state.video_odevler = pd.concat([st.session_state.video_odevler, yeni_v], ignore_index=True)                st.success("Video iletildi.")        with c2:            st.write("#### Kitap Takibi")            k_ad = st.text_input("Kitap Adı")            if st.button("Kitabı Tanımla"):                st.success("Kitap eklendi.")# ==========================================# 🎓 MODÜL 2: ÖĞRENCİ PORTALI# ==========================================else:    st.title("🎓 Öğrenci Başarı Karargahı")    otabs = st.tabs(["🧮 Net & Hedef", "📅 Programım", "🧠 Rehberlik Testleri", "📺 Videolarım", "🎯 Soru Girişi"])    with otabs[0]: # NET HESAPLAMA        st.subheader("🔍 Kaç Net Lazım?")        c1, c2 = st.columns(2)        tm = c1.number_input("TYT Mat", 0.0, 40.0); tt = c1.number_input("TYT Tür", 0.0, 40.0)        am = c2.number_input("AYT Mat", 0.0, 40.0); af = c2.number_input("AYT Alan", 0.0, 40.0)        puan = ((tm + tt) * 1.3 + (am + af) * 3.0) + 230        st.header(f"Tahmini Puanın: {puan:.2f}")    with otabs[1]: # PROGRAM        st.subheader("📅 Ödev Listem")        if not st.session_state.program.empty:            for i, r in st.session_state.program.iterrows():                if r["Durum"] == "Bekliyor":                    c_p1, c_p2 = st.columns([4, 1])                    c_p1.warning(f"📌 **{r['Ders']}** | {r['Konu']} (Değer: {r['Soru Yükü']} Soru)")                    if c_p2.button("Bitti", key=f"u_{i}"):                        st.session_state.program.at[i, "Durum"] = "Tamamlandı"; st.rerun()    with otabs[2]: # REHBERLİK        st.subheader("🧠 Testleri Çöz")        t_sec = st.selectbox("Test Seç", list(REHBERLIK_SORULARI.keys()))        t_skor = 0        with st.form("pdr_f"):            for q in REHBERLIK_SORULARI[t_sec]:                ans = st.select_slider(q, options=["Hiç", "Az", "Orta", "Çok", "Tamamen"], value="Orta")                p = {"Hiç":0, "Az":5, "Orta":10, "Çok":15, "Tamamen":20}; t_skor += p[ans]            o_onay = st.selectbox("İsmin", ogrenci_listesi)            if st.form_submit_button("Gönder"):                yeni_r = pd.DataFrame([[datetime.now().strftime("%d/%m"), o_onay, t_sec, t_skor]], columns=st.session_state.test_sonuclari.columns)                st.session_state.test_sonuclari = pd.concat([st.session_state.test_sonuclari, yeni_r], ignore_index=True)                st.balloons(); st.success("İletildi!")    with otabs[3]: # VİDEO        st.subheader("📺 Sana Atanan Videolar")        if not st.session_state.video_odevler.empty:            for i, r in st.session_state.video_odevler.iterrows():                st.success(f"🎥 {r['Başlık']}")                st.link_button("İzle", r['Link'])    with otabs[4]: # SORU GİRİŞİ (GERİ GELDİ)        st.subheader("🎯 Günlük D-Y-B Girişi")        with st.form("s_f"):            sd = st.selectbox("Ders", ["Matematik", "Türkçe", "Fen", "Sosyal"])            c_s1, c_s2, c_s3 = st.columns(3)            d = c_s1.number_input("D", 0); y = c_s2.number_input("Y", 0); b = c_s3.number_input("B", 0)            if st.form_submit_button("Veriyi Kaydet"):                yeni_s = pd.DataFrame([[datetime.now().date(), "Öğrenci", sd, d, y, b]], columns=st.session_state.soru_takip.columns)                st.session_state.soru_takip = pd.concat([st.session_state.soru_takip, yeni_s], ignore_index=True)                st.success("Kaydedildi!")